package io.lievit.wire;

import java.util.ArrayList;
import java.util.List;

import io.lievit.LievitAction;
import io.lievit.LievitComponent;
import io.lievit.LievitProperty;
import io.lievit.LievitRender;
import io.lievit.Wire;

/**
 * {@code accordion}: the server-first WIRE replacement for the {@code <lv-accordion>} Lit island
 * (ADR-0012, Wave 2). A disclosure GROUP: several triggers, each expanding / collapsing its own
 * region; the open set lives here in typed Java, not in client memory, and the server re-renders
 * the template on each toggle (the client morphs the result, preserving focus + scroll). It is the
 * same disclosure idea as {@code collapsible}, composed over many items.
 *
 * <p>WHY server-state: the island held the open set in a Lit reactive {@code Set} and projected
 * each panel through a named {@code <slot>}, which is inert in light DOM, so the panel bodies
 * silently never rendered (the bug class ADR-0012 was written to kill). Here {@link #open} is a
 * {@code @Wire} list round-tripped in the signed snapshot, and the panel bodies are plain
 * server-rendered JTE owned by the template: they cannot fail to project.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the toggle is a
 * {@code @LievitAction}; the disclosure a11y (WAI-ARIA APG accordion, the same Radix source the
 * island cited) lives in the template. Because a regular {@code @LievitAction} takes no forwarded
 * arguments (only the magic {@code $set}/{@code $toggle} parse inline args, runtime parity gap), the
 * clicked item is ARMED into {@link #toggleId} via {@code l:click="$set('toggleId','<id>')"} (the
 * canonical Livewire {@code wire:click="$set(...)"} idiom this repo already uses for row-arm in
 * {@code listing-list.jte}); {@link #applyToggle()} then flips that id in the open set on the
 * pre-render hook and clears the arm, so the whole interaction is one click, fully server-side, and
 * idempotent under replay (a cleared arm re-renders to a no-op). The same logic is reachable as the
 * explicit {@link #toggle()} action driven by a render-asserting IT.
 *
 * <p>The item ids + labels are server config ({@code @LievitProperty(locked = true)} so a client
 * cannot inject or rename an item); the panel bodies are OWNED template markup (the server-first
 * equivalent of children, not a {@code <slot>}). Copied in by {@code lievit add accordion}: the
 * adopter OWNS this class AND {@code accordion.jte} (rename the package, change the items, put real
 * panel markup in the owned regions).
 */
@LievitComponent(template = "lievit/accordion")
public class AccordionComponent {

    /**
     * Item ids in render order. Locked: the set of items is server config, a client cannot add,
     * remove, or rename one by editing the snapshot. Paired index-for-index with {@link #labels}.
     */
    @Wire
    @LievitProperty(locked = true)
    public List<String> itemIds = new ArrayList<>();

    /** Trigger labels, index-aligned with {@link #itemIds}. Locked alongside the ids. */
    @Wire
    @LievitProperty(locked = true)
    public List<String> labels = new ArrayList<>();

    /**
     * The currently open item ids. The single piece of disclosure state, held server-side and
     * round-tripped as a plain JSON list. For {@code single} mode it holds at most one id.
     */
    @Wire
    public List<String> open = new ArrayList<>();

    /**
     * {@code "single"} (default): at most one item open at a time; {@code "multiple"}: any number.
     * Locked: the selection mode is server policy, not a client toggle.
     */
    @Wire
    @LievitProperty(locked = true)
    public String mode = "single";

    /**
     * The item a click just armed (via the {@code $set} magic). Consumed + cleared by
     * {@link #applyToggle()} on the next render, so a click reduces to one server round-trip. Empty
     * when no toggle is pending; it never persists across a render.
     */
    @Wire
    public String toggleId = "";

    /**
     * Flips the armed {@link #toggleId} in the open set on every pre-render (the hook the dispatcher
     * runs at mount and before each re-render), then clears the arm. Empty arm = no-op, so a plain
     * re-render (or a snapshot replay carrying a cleared arm) never double-toggles: idempotent.
     */
    @LievitRender
    void applyToggle() {
        if (toggleId.isEmpty() || !itemIds.contains(toggleId)) {
            toggleId = "";
            return;
        }
        flip(toggleId);
        toggleId = "";
    }

    /**
     * Toggles the open/closed state of {@link #toggleId} (the armed item) explicitly. Same effect as
     * the {@code $set}-armed render path: provided so a caller (or a render-asserting test) can drive
     * the transition through the {@code @LievitAction} dispatch with the target supplied as a field
     * update in the same wire call (updates apply before actions, ADR-0001). Clears the arm after.
     */
    @LievitAction
    public void toggle() {
        if (!toggleId.isEmpty() && itemIds.contains(toggleId)) {
            flip(toggleId);
        }
        toggleId = "";
    }

    /** Adds the id to the open set, or removes it if already open; single mode keeps at most one. */
    private void flip(String id) {
        if (open.contains(id)) {
            open.remove(id);
            return;
        }
        if ("single".equals(mode)) {
            open.clear();
        }
        open.add(id);
    }

    /**
     * Whether an item is currently open (read by the template to render aria-expanded + the panel
     * hidden attribute).
     *
     * @param id the item id
     * @return true when the item is in the open set
     */
    public boolean isOpen(String id) {
        return open.contains(id);
    }
}

@import gg.jte.Content
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui alert partial -- an inline message banner whose severity drives colour + role.

  TIER: STATIC presentational -> JTE partial. The former <lv-alert> island held no client
  state; severity-to-colour and severity-to-role are both pure functions of the variant, so
  the server renders the whole thing.

  STRUCTURE (scientific decision rule): WAI-ARIA alert / status pattern. shadcn renders a
  bordered tinted panel keyed on variant; the live-region ROLE is the load-bearing decision
  and is taken from the APG: time-sensitive errors (destructive / warning) are assertive
  (role="alert"), informational kinds (info / success) are polite (role="status"), so a
  screen reader interrupts only for the urgent kinds. The tint uses color-mix over the
  severity token so one token drives border + background coherently. The error variant is
  named "destructive" to match shadcn's variant contract (was "danger").

  A11y (WAI-ARIA alert/status): destructive|warning => role="alert" (assertive); info|success =>
  role="status" (polite). An optional heading is rendered first; the message is the content slot.

  Params:
    String variant         = "info"   "info" | "success" | "warning" | "destructive".
    String heading         = null     optional bold heading rendered above the message.
    gg.jte.Content content            the message body.
    String cssClass        = ""       extra utility classes on the banner.

  Usage:
    @@template.lievit.alert(variant = "destructive", content = @@`Could not save the listing.`)
    @@template.lievit.alert(variant = "success", heading = "Saved", content = @@`Your changes are live.`)
--%>
@param String variant = "info"
@param String heading = null
@param gg.jte.Content content
@param String cssClass = ""

!{var urgent = "destructive".equals(variant) || "warning".equals(variant);}
!{var tone = switch (variant) {
    case "success"     -> "var(--lv-color-success)";
    case "warning"     -> "var(--lv-color-warning)";
    case "destructive" -> "var(--lv-color-destructive)";
    default            -> "var(--lv-color-info)";
  };}

<div
  data-slot="alert"
  data-variant="${variant}"
  role="${urgent ? "alert" : "status"}"
  class="block rounded-[var(--lv-radius-md)] border px-[var(--lv-space-4)] py-[var(--lv-space-3)] text-[length:var(--lv-text-sm)] leading-[var(--lv-leading)] text-[var(--lv-color-fg)] ${cssClass}"
  style="font-family:var(--lv-font-sans);border-color:${tone};background:color-mix(in srgb, ${tone} 12%, var(--lv-color-bg));"
>
  @if(heading != null && !heading.isBlank())
    <div data-slot="alert-title" class="mb-[var(--lv-space-1)] font-[var(--lv-font-semibold)]">${heading}</div>
  @endif
  ${content}
</div>

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */
package io.lievit.wire;

import io.lievit.LievitAction;
import io.lievit.LievitComponent;
import io.lievit.LievitProperty;
import io.lievit.Wire;

/**
 * {@code alert-dialog}: the server-first WIRE confirm-modal, the {@code role="alertdialog"}
 * specialization of the dialog wire (ADR-0012, Wave 3). It is the interruptive prompt that demands
 * a response (delete this? discard changes?): a title, a description, a destructive-or-primary
 * confirm button and a cancel button, whose open-state lives here in typed Java, not in client
 * memory. The server re-renders the template on {@link #open()} / {@link #confirm()} /
 * {@link #cancel()} and the client morphs the result.
 *
 * <p>WHY a separate component and not the plain {@link DialogComponent}: WAI-ARIA distinguishes
 * {@code role="dialog"} (general) from {@code role="alertdialog"} (an interruptive prompt requiring
 * a response). A confirm is the alertdialog case, so the template sets {@code role="alertdialog"}
 * and the footer is NOT an owned free-form region but two real, named buttons (the destructive
 * action + cancel) wired with {@code l:click}. It builds ON the dialog wire's model (the same
 * server-held open-state + the owned-body finding from Wave 2), specialized for the confirm shape.
 *
 * <p>WHY it composes the dialog wire's STRUCTURE rather than the dialog COMPONENT: a wire template
 * is rendered with ONLY its own {@code @Wire} fields + {@code _component} (JteTemplateAdapter, the
 * Wave 0 finding), so one wire component cannot render another wire component as a nested live
 * instance with a fresh snapshot. The server-first equivalent of "compose the dialog" is therefore
 * to render the dialog's overlay/panel STRUCTURE (the {@code role}, the {@code aria-modal}, the
 * {@code hidden}-when-closed overlay, the title/description header) inside this component's own
 * owned template, specialized to {@code role="alertdialog"} with the confirm footer. The result is
 * a single self-contained wire component with no {@code <lv-dialog>} reference anywhere.
 *
 * <p>Convention (blueprint 1.b): state is {@code @Wire public} fields; the actions are
 * {@code @LievitAction} methods; the modal a11y (WAI-ARIA APG alertdialog: {@code role=alertdialog},
 * {@code aria-modal}, {@code aria-labelledby} -> the title, {@code aria-describedby} -> the
 * description) lives in the template. {@code title} + {@code description} + the button labels +
 * {@code open} round-trip; {@code destructive} is locked so a client cannot downgrade a
 * server-mandated destructive confirm to a benign one (or vice-versa) by editing the snapshot.
 *
 * <p>WHAT happens on confirm is the adopter's: {@link #confirmed} is a wire flag the host page reads
 * after the round-trip (or the adopter overrides {@link #confirm()} to run the destructive operation
 * server-side, with authz, before closing). Either way the server stays the single owner of the
 * outcome; the client only fires the action.
 *
 * <p>Copied in by {@code lievit add alert-dialog}: the adopter OWNS this class (rename it, move the
 * package, do the real work in {@link #confirm()} with server-side authz) AND the
 * {@code alert-dialog.jte} template.
 */
@LievitComponent(template = "lievit/alert-dialog")
public class AlertDialogComponent {

    /** Open state: the single piece of modal state, held server-side. */
    @Wire
    public boolean open = false;

    /** The prompt headline; wired to {@code aria-labelledby}. Round-trips. */
    @Wire
    public String title = "Are you sure?";

    /** The supporting explanation; wired to {@code aria-describedby}. Empty omits it. Round-trips. */
    @Wire
    public String description = "";

    /** The confirm button label. Round-trips. */
    @Wire
    public String actionLabel = "Confirm";

    /** The cancel button label. Round-trips. */
    @Wire
    public String cancelLabel = "Cancel";

    /**
     * When true the confirm button is the destructive (red) affordance + the title carries a
     * triangle-alert icon. Locked so a client cannot flip a server-mandated destructive confirm to a
     * benign one (or vice-versa) by editing the snapshot payload.
     */
    @Wire
    @LievitProperty(locked = true)
    public boolean destructive = false;

    /**
     * Set true once {@link #confirm()} has run, false again on {@link #cancel()} / {@link #open()}.
     * The host page reads this after the round-trip to learn the outcome; an adopter that does the
     * destructive work directly in {@link #confirm()} can ignore it.
     */
    @Wire
    public boolean confirmed = false;

    /** Opens the prompt, clearing any prior outcome so a re-open starts unanswered. */
    @LievitAction
    public void open() {
        confirmed = false;
        open = true;
    }

    /**
     * Confirms the prompt: records the outcome and closes. The adopter overrides this to run the
     * destructive operation server-side (with authz) before it closes; doing it here keeps the
     * server the single owner of the outcome.
     */
    @LievitAction
    public void confirm() {
        confirmed = true;
        open = false;
    }

    /** Cancels the prompt: clears the outcome and closes. */
    @LievitAction
    public void cancel() {
        confirmed = false;
        open = false;
    }
}

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 */

/**
 * overlay enhancer (ADR-0012, server-first): the ONE CSP-clean typed-TS module that gives the whole
 * server-first modal-overlay family -- `dialog`, `sheet`, `drawer`, `alert-dialog` -- the three
 * client behaviours a modal owes by WAI-ARIA APG that the server cannot do (they are pure
 * focus-mechanics, not state): focus-trap, Escape-to-close, and return-focus.
 *
 * The open/closed STATE stays server-owned (the wire `@Wire boolean open`): the overlay root carries
 * the boolean `hidden` attribute, the server flips it on `open`/`close`, the client morphs it. This
 * module never decides open-state and never round-trips the wire to set it. It only:
 *
 *   - **traps Tab** inside `[data-lv-<kind>-panel]` while the overlay is shown (Tab past the last
 *     focusable wraps to the first, Shift+Tab past the first wraps to the last), so keyboard focus
 *     cannot leak to the page behind the modal (APG "Keyboard Interaction" for a modal dialog);
 *   - **routes Escape to the server close path** by clicking the overlay's own dismiss button -- the
 *     real `l:click="close"` / `l:click="cancel"` button the template already renders. Escape thus
 *     takes the SAME path as the button: the runtime's `l:click` directive fires the wire action and
 *     the server re-renders `hidden`. This keeps the enhancer fully decoupled from the wire codec
 *     (it touches no snapshot, no dispatcher) and CSP-clean (it attaches listeners in code; the
 *     strict CSP refuses inline `on*=` handlers). A non-dismissible dialog (no dismiss button)
 *     simply has no Escape target, matching the locked server `dismissible=false`;
 *   - **moves focus in on open and restores it on close**, observing the `hidden` attribute via a
 *     MutationObserver (the server is the only writer of `hidden`, so observing it is how the client
 *     learns the state changed). On open it remembers `document.activeElement` (the trigger) and
 *     focuses the panel's initial element; on close it returns focus to that remembered opener.
 *
 * Initial-focus rule (APG): focus the element marked `[data-lv-autofocus]` if present, else the
 * first focusable in the panel. An alert-dialog is interruptive, so its template marks the CANCEL
 * button `[data-lv-autofocus]` (focus-on-cancel default, the safe choice for a destructive prompt);
 * a plain dialog focuses its first focusable, falling back to the panel itself (`tabindex=-1`).
 *
 * Idempotent: call {@link enhanceOverlay} once per root (it marks each root) and again after a DOM
 * swap; already-enhanced roots are skipped. {@link enhanceAllOverlays} wires every overlay on the
 * page. One module, the whole family: dialog/sheet/drawer/alert-dialog all share these mechanics.
 */

/** The four server-first modal overlays this module enhances (their root data-* hooks). */
const OVERLAY_KINDS = ["dialog", "sheet", "drawer", "alert-dialog"] as const;
type OverlayKind = (typeof OVERLAY_KINDS)[number];

const ENHANCED = "data-lv-overlay-enhanced";
const RETURN_FOCUS = "_lvOverlayReturnFocus";

/** The CSS selector that matches every modal-overlay root (the union of the four kinds). */
const ROOT_SELECTOR = OVERLAY_KINDS.map((k) => `[data-lv-${k}]`).join(",");

/** Elements that can hold keyboard focus inside a panel (the standard focus-trap set). */
const FOCUSABLE =
  'a[href],area[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),' +
  'textarea:not([disabled]),[tabindex]:not([tabindex="-1"]),[contenteditable="true"]';

/** A root augmented with the opener it must return focus to on close. */
type OverlayRoot = HTMLElement & { [RETURN_FOCUS]?: Element | null };

/** The overlay kind of a root (which `data-lv-<kind>` it carries), or null if it is not an overlay. */
function kindOf(root: HTMLElement): OverlayKind | null {
  return OVERLAY_KINDS.find((k) => root.hasAttribute(`data-lv-${k}`)) ?? null;
}

/** The role=dialog|alertdialog panel of an overlay root. */
function panelOf(root: HTMLElement, kind: OverlayKind): HTMLElement | null {
  return root.querySelector<HTMLElement>(`[data-lv-${kind}-panel]`);
}

/**
 * The button whose click runs the server close/cancel path. Prefer an explicit dismiss button
 * (`-close` for dialog/sheet/drawer); an alert-dialog has no `-close`, its Escape routes to
 * `-cancel`. Returns null for a non-dismissible dialog (no dismiss affordance is rendered).
 */
function dismissButtonOf(root: HTMLElement, kind: OverlayKind): HTMLButtonElement | null {
  return (
    root.querySelector<HTMLButtonElement>(`[data-lv-${kind}-close]`) ??
    root.querySelector<HTMLButtonElement>(`[data-lv-${kind}-cancel]`)
  );
}

/** True when the overlay is shown (the server did not set the boolean `hidden`). */
function isOpen(root: HTMLElement): boolean {
  return !root.hasAttribute("hidden");
}

/** The visible, focusable elements inside a panel, in DOM order. */
function focusablesIn(panel: HTMLElement): HTMLElement[] {
  return Array.from(panel.querySelectorAll<HTMLElement>(FOCUSABLE)).filter(
    (el) => el.offsetParent !== null || el === document.activeElement
  );
}

/** Move focus to the panel's initial element (its `[data-lv-autofocus]`, else first focusable, else the panel). */
function focusInitial(panel: HTMLElement): void {
  const marked = panel.querySelector<HTMLElement>("[data-lv-autofocus]");
  const target = marked ?? focusablesIn(panel)[0];
  if (target) {
    target.focus();
    return;
  }
  // No focusable child: make the panel itself focusable and focus it (APG fallback).
  if (!panel.hasAttribute("tabindex")) {
    panel.setAttribute("tabindex", "-1");
  }
  panel.focus();
}

/** Return focus to the element that had it when the overlay opened (the trigger). */
function restoreFocus(root: OverlayRoot): void {
  const opener = root[RETURN_FOCUS];
  if (opener instanceof HTMLElement && opener.isConnected) {
    opener.focus();
  }
  root[RETURN_FOCUS] = null;
}

/** Keep Tab within the panel: wrap from last->first (Tab) and first->last (Shift+Tab). */
function trapTab(event: KeyboardEvent, panel: HTMLElement): void {
  const focusables = focusablesIn(panel);
  if (focusables.length === 0) {
    // Nothing focusable: keep focus on the panel, never leak to the page behind.
    event.preventDefault();
    panel.focus();
    return;
  }
  const first = focusables[0];
  const last = focusables[focusables.length - 1];
  const active = document.activeElement;
  if (event.shiftKey && (active === first || !panel.contains(active))) {
    event.preventDefault();
    last.focus();
  } else if (!event.shiftKey && active === last) {
    event.preventDefault();
    first.focus();
  }
}

/**
 * Enhance one overlay root: trap Tab + route Escape to the server close path + drive focus on the
 * open<->close transition. No-op if it is already enhanced or not a modal overlay root.
 *
 * @param root a `[data-lv-dialog|sheet|drawer|alert-dialog]` overlay root
 */
export function enhanceOverlay(root: HTMLElement): void {
  if (root.hasAttribute(ENHANCED)) {
    return;
  }
  const kind = kindOf(root);
  if (kind === null) {
    return;
  }
  root.setAttribute(ENHANCED, "");

  const panel = panelOf(root, kind);
  if (panel === null) {
    return;
  }

  // Tab-trap + Escape: a single keydown listener on the root (the panel lives inside it).
  root.addEventListener("keydown", (event: KeyboardEvent) => {
    if (!isOpen(root)) {
      return;
    }
    if (event.key === "Tab") {
      trapTab(event, panel);
      return;
    }
    if (event.key === "Escape") {
      const dismiss = dismissButtonOf(root, kind);
      if (dismiss) {
        // Route Escape through the SAME server path as the button (its l:click action).
        event.preventDefault();
        dismiss.click();
      }
    }
  });

  // Focus management across the server-owned open<->close transition: the server writes `hidden`,
  // we observe it. On open: remember the opener + focus the initial element. On close: restore.
  const holder = root as OverlayRoot;
  const observer = new MutationObserver(() => {
    if (isOpen(root)) {
      if (!holder[RETURN_FOCUS]) {
        holder[RETURN_FOCUS] = document.activeElement;
      }
      focusInitial(panel);
    } else if (holder[RETURN_FOCUS]) {
      restoreFocus(holder);
    }
  });
  observer.observe(root, { attributes: true, attributeFilter: ["hidden"] });

  // If the root mounted already-open (SSR open=true), focus it now without waiting for a mutation.
  if (isOpen(root)) {
    holder[RETURN_FOCUS] = document.activeElement;
    focusInitial(panel);
  }
}

/** Enhance every modal overlay on the page (call on load + after DOM swaps). Idempotent. */
export function enhanceAllOverlays(scope: ParentNode = document): void {
  scope
    .querySelectorAll<HTMLElement>(ROOT_SELECTOR)
    .forEach((root) => enhanceOverlay(root));
}

@import gg.jte.Content
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui badge partial -- a small status pill, the gestionale status indicator.

  TIER: STATIC presentational -> JTE partial (ADR-0012 server-first pivot). The former
  <lv-badge> island held no client state; variant-to-colour is a pure function of the
  variant, so the server renders the whole pill. The Lit island is gone; this is the to-be.

  STRUCTURE (scientific decision rule): shadcn's Badge is a single styled <span> keyed on a
  variant. Two variant families ship side by side so a retheme retints every pill from the
  tokens: (a) the SHADCN taxonomy -- `default` (primary fill), `secondary`, `destructive`,
  `outline` -- so an adopter coming from shadcn names the same variants; (b) the STATUS family
  the gestionale uses -- success / warning / danger / info -- plus a muted `neutral` default.
  Every variant drives a fill + foreground (and, for `outline`, a transparent fill + border)
  token pair, exactly the mapping the dropped island shipped extended with the shadcn names.
  The label is plain text (the common kit call: @@template.lievit.badge(variant=.., label="..")),
  with an optional Content slot for rich children that takes precedence when supplied (the
  same content-over-scalar precedence kbd.jte uses).

  asChild (server-first polymorphism): shadcn's Badge takes `asChild` to render as a different
  element (most commonly an <a> link). The server already knows whether the pill is a link, so
  instead of a render-prop we pass `href`: a non-blank href renders the pill as a real <a> (the
  browser navigates, middle-click + open-in-new-tab work, with a focus-visible ring) while a
  blank href keeps the inert <span>. Same markup + tokens either way; the only delta is the
  element + its interaction affordances -- the server-first equivalent of shadcn's asChild anchor.

  CSS COMPAT: the pill keeps the `lv-badge lv-badge--<variant>` class names the island used,
  so any stylesheet that targeted them still applies; the partial is self-styling via inline
  token-driven CSS (no external rule needed), consistent with the other w1a partials.

  A11y: a status pill is decorative text; it carries no role (it is not a live region -- the
  surrounding context, e.g. a table cell or an alert, owns any announcement). Colour is never
  the only signal: the label text always states the status. When `href` is set the pill becomes
  a real focusable link, so it gains the platform's anchor semantics + a focus-visible ring.

  Params:
    String variant         = "neutral"  shadcn: "default" | "secondary" | "destructive" | "outline";
                                        status: "neutral" | "success" | "warning" | "danger" | "info".
    String label           = null       the pill text (used when no content slot is supplied).
    gg.jte.Content content              optional rich children; takes precedence over label.
    String href            = null       non-blank => render as an <a> link (asChild), else a <span>.
    String cssClass        = ""         extra utility classes on the pill.

  Usage:
    @@template.lievit.badge(variant = "success", label = "Attivo")
    @@template.lievit.badge(variant = "secondary", label = "Draft")
    @@template.lievit.badge(variant = "outline", label = "v2")
    @@template.lievit.badge(variant = "danger", content = @@`<strong>Scaduto</strong>`)
    @@template.lievit.badge(variant = "default", label = "Open issue", href = "/issues/42")
--%>
@param String variant = "neutral"
@param String label = null
@param gg.jte.Content content = null
@param String href = null
@param String cssClass = ""

!{var bg = switch (variant) {
    case "default"     -> "var(--lv-color-primary)";
    case "secondary"   -> "var(--lv-color-secondary)";
    case "destructive" -> "var(--lv-color-destructive)";
    case "outline"     -> "transparent";
    case "success"     -> "var(--lv-color-success)";
    case "warning"     -> "var(--lv-color-warning)";
    case "danger"      -> "var(--lv-color-danger)";
    case "info"        -> "var(--lv-color-info)";
    default            -> "var(--lv-color-surface)";
  };}
!{var fg = switch (variant) {
    case "default"     -> "var(--lv-color-primary-fg)";
    case "secondary"   -> "var(--lv-color-secondary-fg)";
    // shadcn's Badge destructive is text-white. The destructive-fg token resolves to white,
    // so it gives the same white-on-red pill while staying token-driven (no hardcoded hex --
    // the kit's law + the no-hex test gate). Same visual as shadcn, retheme-safe.
    case "destructive" -> "var(--lv-color-destructive-fg)";
    case "outline"     -> "var(--lv-color-fg)";
    case "success"     -> "var(--lv-color-success-fg)";
    case "warning"     -> "var(--lv-color-warning-fg)";
    case "danger"      -> "var(--lv-color-danger-fg)";
    case "info"        -> "var(--lv-color-info-fg)";
    default            -> "var(--lv-color-muted)";
  };}
!{var border = "outline".equals(variant) ? "var(--lv-color-border)" : "transparent";}
!{var isLink = href != null && !href.isBlank();}
!{var pillClass = "lv-badge lv-badge--" + variant + " inline-flex items-center gap-[var(--lv-space-1)] rounded-full border px-[var(--lv-space-2)] py-[var(--lv-space-1)] text-[length:var(--lv-text-sm)] font-[var(--lv-font-medium)] leading-none focus-visible:outline-none focus-visible:shadow-[var(--lv-ring)] " + cssClass;}
!{var pillStyle = "font-family:var(--lv-font-sans);background:" + bg + ";color:" + fg + ";border-color:" + border + ";";}

@if(isLink)
<a
  href="${href}"
  data-slot="badge"
  data-variant="${variant}"
  class="${pillClass} no-underline transition-colors hover:opacity-90"
  style="${pillStyle}"
>@if(content != null)${content}@else${label}@endif</a>
@else
<span
  data-slot="badge"
  data-variant="${variant}"
  class="${pillClass}"
  style="${pillStyle}"
>@if(content != null)${content}@else${label}@endif</span>
@endif

@import java.util.List
@import java.util.Map
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui breadcrumb partial -- an accessible breadcrumb navigation trail.

  TIER: STATIC presentational -> JTE partial (ADR-0012 server-first pivot). The former
  <lv-breadcrumb> island held no client state; the trail is a fact the SERVER already knows
  (the route being rendered), so the server emits the whole <nav>. The Lit island is gone.

  STRUCTURE (scientific decision rule): WAI-ARIA breadcrumb pattern (the model the dropped
  island cited). A <nav aria-label> landmark wraps an ordered <ol> -- the ordinal list
  communicates the root-to-current sequence to assistive tech. Each non-current item is a real
  <a href> (the browser navigates, middle-click + open-in-new-tab work, no JS); the LAST item
  is the current page, rendered as a non-link <span aria-current="page"> (you cannot navigate
  to where you already are). The separator glyph between items is aria-hidden so a screen
  reader does not announce it. This mirrors the navigation-menu + sidebar partials: real
  anchors, server-known active state, zero client.

  DATA SHAPE: items arrive as a typed List<Map<String,String>>, root-to-current, each map
  keyed `label` (required, the visible text) and `href` (optional, the navigation target).
  The last item is treated as current regardless of whether it carries an href. This is the
  same List<Map<String,String>> idiom the dashboard block uses, so it compiles against the
  bare jte runtime with no custom record type to ship.

  COLLAPSE / ELLIPSIS (shadcn BreadcrumbEllipsis): a long trail collapses its MIDDLE to an
  ellipsis item when `maxItems` > 0 and the trail is longer than it. The server keeps the FIRST
  crumb (the root, the most useful anchor) + the LAST `maxItems - 1` crumbs (the tail, ending at
  the current page) and renders one BreadcrumbEllipsis (an aria-hidden glyph + an sr-only "More")
  in place of the hidden middle. This is the server-pure analogue of shadcn's collapsed dropdown:
  no JS, no client state, the glyph is decorative and the dropped crumbs simply are not rendered
  (the root + tail are what a user navigates by). maxItems = 0 (default) never collapses.

  CSS COMPAT: keeps the `lv-breadcrumb*` class names the island used so any stylesheet that
  targeted them still applies; the partial is self-styling via token-driven utilities.

  Params:
    List<Map<String,String>> items   the trail, root-to-current; each map: label (+ optional href).
    String separator = "/"           the glyph between items (aria-hidden).
    int    maxItems  = 0             > 0 => collapse the middle to an ellipsis past this many crumbs.
    String label     = "Breadcrumb"  aria-label for the <nav> landmark.
    String cssClass  = ""            extra utility classes on the <nav>.

  Usage:
    @@template.lievit.breadcrumb(items = java.util.List.of(
      java.util.Map.of("label", "Home", "href", "/"),
      java.util.Map.of("label", "Properties", "href", "/properties"),
      java.util.Map.of("label", "Via Roma 12")))
    @@template.lievit.breadcrumb(items = deepTrail, maxItems = 3)   // root ... + last two crumbs
--%>
@param List<Map<String, String>> items = java.util.List.of()
@param String separator = "/"
@param int maxItems = 0
@param String label = "Breadcrumb"
@param String cssClass = ""

<%-- Build the render plan: a list of indices into `items`, with -1 marking the collapsed ellipsis.
     No collapse when maxItems <= 0 or the trail already fits; otherwise keep first + last maxItems-1. --%>
!{var plan = new java.util.ArrayList<Integer>();}
!{var n = items.size();}
!{var collapse = maxItems > 0 && n > maxItems;}
@if(collapse)
  !{plan.add(0);}
  !{plan.add(-1);}
  !{var tailStart = n - (maxItems - 1);}
  @for(int i = tailStart; i < n; i++)
    !{plan.add(i);}
  @endfor
@else
  @for(int i = 0; i < n; i++)
    !{plan.add(i);}
  @endfor
@endif

<nav
  data-slot="breadcrumb"
  aria-label="${label}"
  class="lv-breadcrumb block text-[length:var(--lv-text-sm)] ${cssClass}"
  style="font-family:var(--lv-font-sans);"
>
  <ol data-slot="breadcrumb-list" class="lv-breadcrumb__list m-0 flex list-none flex-wrap items-center p-0">
    @for(var pos = 0; pos < plan.size(); pos++)
      !{var idx = plan.get(pos);}
      !{var isFirst = pos == 0;}
      @if(idx == -1)
        <li data-slot="breadcrumb-item" class="lv-breadcrumb__item inline-flex items-center">
          @if(!isFirst)
            <span class="lv-breadcrumb__separator select-none px-[var(--lv-space-2)] text-[var(--lv-color-muted)]" aria-hidden="true">${separator}</span>
          @endif
          <span data-slot="breadcrumb-ellipsis" role="presentation" aria-hidden="true" class="lv-breadcrumb__ellipsis inline-flex items-center text-[var(--lv-color-muted)]">
            @template.lievit.icon(name = "ellipsis", size = "1rem")
          </span>
          <span class="sr-only">More</span>
        </li>
      @else
        !{var item = items.get(idx);}
        !{var isCurrent = idx == n - 1;}
        !{var href = item.get("href");}
        <li data-slot="breadcrumb-item" class="lv-breadcrumb__item inline-flex items-center">
          @if(!isFirst)
            <span class="lv-breadcrumb__separator select-none px-[var(--lv-space-2)] text-[var(--lv-color-muted)]" aria-hidden="true">${separator}</span>
          @endif
          @if(isCurrent)
            <span data-slot="breadcrumb-page" class="lv-breadcrumb__current font-[var(--lv-font-medium)] text-[var(--lv-color-muted)]" aria-current="page">${item.getOrDefault("label", "")}</span>
          @else
            <a data-slot="breadcrumb-link" class="lv-breadcrumb__link rounded-[var(--lv-radius-sm)] text-[var(--lv-color-primary)] no-underline hover:underline focus-visible:shadow-[var(--lv-ring)] focus-visible:outline-none" href="${href == null ? "#" : href}">${item.getOrDefault("label", "")}</a>
          @endif
        </li>
      @endif
    @endfor
  </ol>
</nav>

@import gg.jte.Content
@import gg.jte.output.StringOutput
@import gg.jte.html.escape.Escape
<%--
  Copyright 2026 Francesco Bilotta
  Licensed under the Apache License, Version 2.0 (the "License").

  lievit-ui button partial -- a token-styled button (or link styled as a button).

  TIER: STATIC presentational -> JTE partial. The former <lv-button> island only styled a
  native <button>; it held no state. Crucially the CLICK is NOT the partial's concern: the
  consuming wire template wires the action via l:click on the element (l:click="save"), or a
  plain form submit / <a href> drives navigation. The partial renders only the styled control.

  STRUCTURE (scientific decision rule): a real native <button> (or <a> when href is given),
  which carries the button role, Enter/Space activation and disabled semantics for free
  (WAI-ARIA APG button), so no manual ARIA is needed -- exactly shadcn's Button, whose only
  job is the cva variant styling. Rendering an <a> when href is set keeps a navigational
  action a real link (right-click, middle-click, copy-URL all work) instead of a JS-only button.

  SIZE (Filament parity, the toolbar-alignment decision). The button is HEIGHT-based, not
  padding-based, so it sits flush next to the form controls in a toolbar row. The baseline is
  shadcn's 36px control height; each size pins the SAME height token the form controls use, so a
  button lines up pixel-exact with an input / native-select of the matching size:
    sm  -> height token [var(--lv-space-8)]  (2rem,   32px) == native-select size="sm"      ; compact toolbar
    md  -> height token [var(--lv-space-9)]  (2.25rem,36px) == input + native-select default ; THE default, the shadcn 36px row baseline
    lg  -> height token [var(--lv-space-10)] (2.5rem, 40px) == native-select size="lg"      ; prominent CTA
  Horizontal padding + text size scale with the height; the gap-[var(--lv-space-2)] spaces an
  icon from its label. md matches `@template.lievit.input` and `@template.lievit.native-select` (default) so a
  toolbar of [input][native-select][button] aligns with no per-call height hacks (the bug this
  fixes: adopters hand-rolling fixed-height buttons with ad-hoc padding that never lined up with
  the inputs).

  ICON-ONLY (toolbar icon actions + per-row action icons). Set iconOnly=true to render a SQUARE
  icon-only control: width == height for the chosen size (h/w = the same --lv-space token), zero
  horizontal padding, the content is a single @template.lievit.icon(...). It is the SAME real
  <button>/<a> element, so role/keyboard/disabled/focus-ring are unchanged. Because there is no
  visible text label, ariaLabel is REQUIRED for the accessible name (WAI-ARIA): an icon-only
  control with no name is unusable to assistive tech, so it is a first-class param here.

  A11y (WAI-ARIA button): native <button> => role + keyboard + disabled for free; <a href> =>
  a real link. focus-visible ring via the --lv-ring token. A disabled link drops href and gets
  aria-disabled (an <a> cannot be natively disabled). ariaLabel sets aria-label (mandatory for
  iconOnly, optional otherwise).

  EXTRA ATTRIBUTES -- two channels, by trust (the XSS decision rule). The control often needs
  more than the typed params: wire directives (l:click, l:keydown), data-*, target/rel. There
  are TWO ways in, split by who controls the value, because escaping is not optional for the
  dynamic case:
    * attrs (TRUSTED, raw) -- a raw attribute string output with $unsafe, so it lands as markup
      and is NOT escaped. Use it ONLY for STATIC, author-controlled strings: wire directives and
      fixed attributes whose every character you typed yourself, e.g.
      attrs = "l:click=\"$set('open','')\" target=\"_blank\" rel=\"noopener\"". NEVER interpolate
      a user/DB-derived value into attrs: a payload that closes the quote and opens a script tag
      ( the classic [quote][gt][script...] breakout ) would escape the tag and inject markup.
    * dataAttrs (SAFE, escaped) -- a Map<String,String> of DYNAMIC data-* attributes. Each entry
      renders as data-<key>="<value>" where the VALUE is escaped with JTE's OWN attribute escaper
      gg.jte.html.escape.Escape.htmlAttribute (the exact routine ContentType.Html uses for a
      ${} in attribute-value position), so a hostile value (the same [quote][gt][script...]
      breakout payload) renders inert: the quote and angle brackets become entities, so it stays
      attribute text and never becomes a tag. (We escape-then-$unsafe rather than write a bare
      @for in the open tag because JTE's HTML parser forbids a loop in attribute-NAME position;
      routing every value through Escape.htmlAttribute keeps the SAME escaping guarantee.) This
      is the ONLY safe way to carry user/DB-derived data on the button. Keys are the
      data-attribute name WITHOUT the leading "data-" (key "confirm" -> data-confirm); keep keys
      to simple identifiers ([A-Za-z][A-Za-z0-9-]*) -- the key sits in
      attribute-NAME position, which JTE does not escape, so a non-identifier key is the caller's
      bug, not an injection the partial absorbs. Empty by default; left empty nothing is added.

  Params:
    String  variant  = "primary"   "primary" | "secondary" | "destructive" | "ghost" | "outline".
    String  size     = "md"        "sm" | "md" | "lg" (height-based, aligns to the form controls).
    boolean iconOnly = false        square icon-only button; content is a single @@template.lievit.icon.
    String  type     = "button"    "button" | "submit" | "reset" (ignored when href is set).
    String  href     = null        when set, render an <a href> styled as a button.
    boolean disabled = false        dims + blocks activation.
    String  ariaLabel = null       aria-label; REQUIRED when iconOnly is true.
    String  cssClass = ""          extra utility classes (e.g. an l:click is added by the caller).
    String  attrs    = ""          TRUSTED raw attribute string ($unsafe) -- STATIC strings only.
    Map<String,String> dataAttrs = {}  SAFE dynamic data-* (key w/o "data-", simple identifier);
                                      each value escaped via Escape.htmlAttribute.
    gg.jte.Content content          the button label / icon + label (a single icon when iconOnly).

  Usage: the consuming wire template wires the action via l:click on the rendered element.
    @@template.lievit.button(variant = "primary", cssClass = "...", content = @@`Save`)
    @@template.lievit.button(size = "sm", variant = "secondary", content = @@`Filter`)
    @@template.lievit.button(href = "/listings", variant = "ghost", content = @@`Back`)
    @@template.lievit.button(iconOnly = true, size = "sm", variant = "ghost", ariaLabel = "Open calendar",
        content = @@`@@template.lievit.icon(name = "calendar", size = "1rem")`)
    (trusted STATIC directive via attrs -- $unsafe, author-typed only):
    @@template.lievit.button(variant = "destructive", attrs = "l:click=\"$set('confirmOpen','')\"", content = @@`Delete`)
    (DYNAMIC user-derived value carried SAFELY -- HTML-escaped -- via dataAttrs):
    @@template.lievit.button(variant = "destructive", dataAttrs = java.util.Map.of("confirm", userSuppliedText),
        attrs = "l:click=\"armReset\"", content = @@`Reset`)
--%>
@param String variant = "primary"
@param String size = "md"
@param boolean iconOnly = false
@param String type = "button"
@param String href = null
@param boolean disabled = false
@param String ariaLabel = null
@param String cssClass = ""
@param String attrs = ""
@param java.util.Map<String, String> dataAttrs = java.util.Map.of()
@param gg.jte.Content content

<%-- per-variant resting colours + the shadcn hover (hover:bg-<tone>/90, secondary /80, ghost+outline
     hover to accent). destructive also pins the aria-invalid destructive ring (shadcn). --%>
!{var variantClass = switch (variant) {
    case "secondary"   -> "bg-[var(--lv-color-secondary)] text-[var(--lv-color-secondary-fg)] hover:bg-[color-mix(in_srgb,var(--lv-color-secondary)_80%,transparent)]";
    case "destructive" -> "bg-[var(--lv-color-destructive)] text-[var(--lv-color-destructive-fg)] hover:bg-[color-mix(in_srgb,var(--lv-color-destructive)_90%,transparent)] aria-invalid:shadow-[var(--lv-ring)]";
    case "ghost"       -> "bg-transparent text-[var(--lv-color-fg)] border-transparent hover:bg-[var(--lv-color-accent)] hover:text-[var(--lv-color-accent-fg)]";
    case "outline"     -> "bg-transparent text-[var(--lv-color-fg)] border-[var(--lv-color-border)] shadow-[var(--lv-shadow-xs)] hover:bg-[var(--lv-color-accent)] hover:text-[var(--lv-color-accent-fg)]";
    default            -> "bg-[var(--lv-color-primary)] text-[var(--lv-color-primary-fg)] hover:bg-[color-mix(in_srgb,var(--lv-color-primary)_90%,transparent)]";
  };}

<%-- height + text-size per size; horizontal padding is added separately so iconOnly can drop it for a square --%>
!{var sizeClass = switch (size) {
    case "sm" -> "h-[var(--lv-space-8)] text-[length:var(--lv-text-xs)]";
    case "lg" -> "h-[var(--lv-space-10)] text-[length:var(--lv-text-base)]";
    default   -> "h-[var(--lv-space-9)] text-[length:var(--lv-text-sm)]";
  };}
<%-- square (w == h) + no horizontal padding for the icon-only control; otherwise size-scaled px --%>
!{var shapeClass = iconOnly
    ? (switch (size) {
        case "sm" -> "w-[var(--lv-space-8)] p-0";
        case "lg" -> "w-[var(--lv-space-10)] p-0";
        default   -> "w-[var(--lv-space-9)] p-0";
      })
    : (switch (size) {
        case "sm" -> "px-[var(--lv-space-3)]";
        case "lg" -> "px-[var(--lv-space-6)]";
        default   -> "px-[var(--lv-space-4)]";
      });}

<%-- shadcn base: shrink-0 + whitespace-nowrap keep the control intact in a flex toolbar; the
     transition animates only colour + box-shadow (hover + focus ring); aria-invalid recolours
     the border to the destructive token (the per-variant ring is added in variantClass). --%>
!{var base = "inline-flex shrink-0 items-center justify-center gap-[var(--lv-space-2)] whitespace-nowrap rounded-[var(--lv-radius-md)] border border-transparent leading-[var(--lv-leading)] cursor-pointer outline-none transition-[color,box-shadow] focus-visible:shadow-[var(--lv-ring)] aria-invalid:border-[var(--lv-color-destructive)] disabled:opacity-50 disabled:cursor-not-allowed aria-disabled:opacity-50 aria-disabled:cursor-not-allowed";}

<%-- SAFE dynamic data-* attributes. JTE's HTML parser forbids a raw @for in attribute-NAME
     position, so we build the fragment once here: each entry becomes data-<key>="<value>"
     with the VALUE escaped through JTE's OWN attribute escaper (Escape.htmlAttribute, the same
     routine ContentType.Html applies to a ${} in attribute-value position). The result is then
     emitted with $unsafe in the open tag -- safe because every dynamic value is already escaped.
     Keys must be simple identifiers (the key sits in attribute-NAME position, which is NOT
     escaped); a non-identifier key is dropped so it can never inject markup. --%>
!{var dataAttrs_ = new StringOutput();}
!{for (var e : dataAttrs.entrySet()) {
    if (e.getKey() != null && e.getKey().matches("[A-Za-z][A-Za-z0-9-]*")) {
      dataAttrs_.writeContent(" data-" + e.getKey() + "=\"");
      Escape.htmlAttribute(e.getValue() == null ? "" : e.getValue(), dataAttrs_);
      dataAttrs_.writeContent("\"");
    }
  }}
!{var dataAttrsMarkup = dataAttrs_.toString();}

@if(href != null)
  <a
    data-slot="button"
    data-variant="${variant}"
    data-size="${size}"
    data-icon-only="${iconOnly}"
    href="${disabled ? null : href}"
    aria-disabled="${disabled ? "true" : null}"
    aria-label="${ariaLabel}"
    $unsafe{dataAttrsMarkup}
    class="${base} ${sizeClass} ${shapeClass} ${variantClass} ${cssClass}"
    style="font-family:var(--lv-font-sans);"
    $unsafe{attrs}
  >${content}</a>
@else
  <button
    data-slot="button"
    data-variant="${variant}"
    data-size="${size}"
    data-icon-only="${iconOnly}"
    type="${type}"
    disabled="${disabled}"
    aria-label="${ariaLabel}"
    $unsafe{dataAttrsMarkup}
    class="${base} ${sizeClass} ${shapeClass} ${variantClass} ${cssClass}"
    style="font-family:var(--lv-font-sans);"
    $unsafe{attrs}
  >${content}</button>
@endif

